    ''' Return the difference between 2 versions '''
    if before is None:
        return {'prepared': '>> Newly checked out %s' % after}
    elif before != after:
        # Ensure we have the object we are referring to during git diff !
        git_version_used = git_version(gitPath, module)
        fetch(gitPath, module, repo, dest, after, remote, depth, bare, '', git_version_used)
